public static class Settings
{
    public const string ApiToken = "SEM_DEJ_NOVY_TOKEN";
    public const string ApiBase = "https://webapi.teamviewer.com/api/v1";

    public static readonly bool DryRun = false;
    public static readonly bool EnableLogging = true;

    // -1 = every run, otherwise hour 0-23
    public const int RunAtHour = -1;

    public const string PropertyKey = "TeamViewer ID";

    // Ověř podle reálných objektů v Alvao.
    public const int ClassIdDesktop = 3;
    public const int ClassIdNotebook = 145;

    public static readonly bool EnableDetailedNotFoundLogging = false;
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Net.Http;
using System.Net.Http.Headers;
using Microsoft.Data.SqlClient;
using Newtonsoft.Json.Linq;
using Dapper;
using Alvao.Apps.API;
using Alvao.API.Common;
using Alvao.API.AM;
using Alvao.Context;

public class TeamViewerImportPeriodicAction : IPeriodicAction
{
    public string Name { get; set; }

    public TeamViewerImportPeriodicAction()
    {
        Name = "TeamViewer ID Import";
    }

    public void OnPeriod(SqlConnection con)
    {
        var logger = Alvao.API.Internal.TenantDiagnosticsLog.Get();

        if (string.IsNullOrWhiteSpace(Settings.ApiToken))
        {
            logger.Error("TeamViewerImport: ApiToken is empty.");
            return;
        }

        if (Settings.RunAtHour >= 0 && DateTime.Now.Hour != Settings.RunAtHour)
            return;

        var stopwatch = System.Diagnostics.Stopwatch.StartNew();

        LogInfo(logger, "Starting sync. DryRun=" + Settings.DryRun);

        Dictionary<string, TvDevice> tvDevices;

        try
        {
            tvDevices = LoadTeamViewerDevices(logger);
        }
        catch (Exception ex)
        {
            logger.Error(ex, "TeamViewerImport: Failed to load TeamViewer devices: " + ex.Message);
            return;
        }

        LogInfo(logger, "Loaded TeamViewer devices: " + tvDevices.Count);

        List<AlvaoComputer> computers;

        using (var scope = AlvaoContext.GetConnectionScope())
        {
            computers = scope.Connection.Query<AlvaoComputer>(@"
                SELECT n.intNodeId AS NodeId,
                       n.lintClassId AS ClassId,
                       nc.Hostname AS Hostname,
                       nc.TeamviewerId AS CurrentTeamviewerId
                FROM tblNode n
                JOIN NodeCust nc ON nc.NodeId = n.intNodeId
                WHERE n.lintClassId IN (@desktopId, @notebookId)
                  AND n.IsDiscarded = 0
                  AND n.IsRemoved = 0
                  AND nc.Hostname IS NOT NULL
                  AND LTRIM(RTRIM(nc.Hostname)) <> ''",
                new
                {
                    desktopId = Settings.ClassIdDesktop,
                    notebookId = Settings.ClassIdNotebook
                },
                scope.Transaction).ToList();
        }

        LogInfo(logger, "Alvao computers loaded: " + computers.Count);

        int matched = 0;
        int updated = 0;
        int unchanged = 0;
        int notFound = 0;
        int failed = 0;

        var systemPerson = Person.GetSystem();

        foreach (var pc in computers)
        {
            var key = Normalize(pc.Hostname);

            if (string.IsNullOrEmpty(key))
                continue;

            TvDevice tv;

            if (!tvDevices.TryGetValue(key, out tv))
            {
                notFound++;

                if (Settings.EnableDetailedNotFoundLogging)
                {
                    LogInfo(logger,
                        "NOT FOUND: NodeId=" + pc.NodeId +
                        " ClassId=" + pc.ClassId +
                        " Hostname='" + pc.Hostname +
                        "' Key='" + key + "'");
                }

                continue;
            }

            matched++;

            var newValue = tv.TeamviewerId.ToString();

            if (string.Equals(pc.CurrentTeamviewerId, newValue, StringComparison.Ordinal))
            {
                unchanged++;
                continue;
            }

            if (Settings.DryRun)
            {
                updated++;

                LogInfo(logger,
                    "[DRY-RUN] NodeId=" + pc.NodeId +
                    " Hostname='" + pc.Hostname + "'" +
                    " TeamViewerName='" + tv.OriginalName + "'" +
                    " TeamViewerId: '" + (pc.CurrentTeamviewerId ?? "") + "' -> '" + newValue + "'");
                continue;
            }

            try
            {
                var props = new Dictionary<string, object>
                {
                    { Settings.PropertyKey, newValue }
                };

                ObjectProperty.Update(systemPerson.iPersonId, pc.NodeId, props);

                updated++;

                LogInfo(logger,
                    "UPDATED: NodeId=" + pc.NodeId +
                    " Hostname='" + pc.Hostname + "'" +
                    " Property='" + Settings.PropertyKey + "'" +
                    " Value='" + newValue + "'" +
                    " TeamViewerName='" + tv.OriginalName + "'");
            }
            catch (Exception ex)
            {
                failed++;

                logger.Error(ex,
                    "TeamViewerImport: Failed to update NodeId=" + pc.NodeId +
                    " Hostname='" + pc.Hostname + "': " + ex.Message);
            }
        }

        stopwatch.Stop();

        LogInfo(logger,
            "Done in " + stopwatch.Elapsed.TotalSeconds.ToString("F1") + "s." +
            " Matched=" + matched +
            ", Updated=" + updated +
            ", Unchanged=" + unchanged +
            ", NotFound=" + notFound +
            ", Failed=" + failed +
            ", DryRun=" + Settings.DryRun);
    }

    private static Dictionary<string, TvDevice> LoadTeamViewerDevices(NLog.ILogger logger)
    {
        var result = new Dictionary<string, TvDevice>(StringComparer.OrdinalIgnoreCase);

        using (var client = new HttpClient())
        {
            client.Timeout = TimeSpan.FromSeconds(60);
            client.DefaultRequestHeaders.Authorization =
                new AuthenticationHeaderValue("Bearer", Settings.ApiToken);

            LoadManagedDevices(client, result, logger);
            LoadLegacyDevices(client, result, logger);
        }

        return result;
    }

    private static void LoadManagedDevices(HttpClient client, Dictionary<string, TvDevice> result, NLog.ILogger logger)
    {
        int count = 0;
        string url = Settings.ApiBase + "/managed/devices";
        int safety = 0;

        while (!string.IsNullOrEmpty(url) && safety++ < 200)
        {
            var obj = GetJson(client, url);
            var resources = obj["resources"] as JArray;

            if (resources != null)
            {
                foreach (var d in resources)
                {
                    var name = (string)d["name"];
                    var tvId = (long?)d["teamviewerId"];
                    var lastSeen = (DateTime?)d["last_seen"];
                    var isOnline = (bool?)d["isOnline"] ?? false;

                    if (!string.IsNullOrWhiteSpace(name) && tvId.HasValue)
                    {
                        Merge(result, name, tvId.Value, lastSeen, isOnline, "managed");
                        count++;
                    }
                }
            }

            var nextToken = (string)obj["nextPaginationToken"];

            url = string.IsNullOrWhiteSpace(nextToken)
                ? null
                : Settings.ApiBase + "/managed/devices?paginationToken=" + Uri.EscapeDataString(nextToken);
        }

        LogInfo(logger, "Managed devices scanned: " + count);
    }

    private static void LoadLegacyDevices(HttpClient client, Dictionary<string, TvDevice> result, NLog.ILogger logger)
    {
        int count = 0;

        var obj = GetJson(client, Settings.ApiBase + "/devices?full_list=true");
        var devices = obj["devices"] as JArray;

        if (devices != null)
        {
            foreach (var d in devices)
            {
                var alias = (string)d["alias"];
                var tvId = (long?)d["teamviewer_id"];
                var lastSeen = (DateTime?)d["last_seen"];

                var onlineState = ((string)d["online_state"]) ?? "";
                bool isOnline = onlineState.Equals("online", StringComparison.OrdinalIgnoreCase);

                if (!string.IsNullOrWhiteSpace(alias) && tvId.HasValue)
                {
                    Merge(result, alias, tvId.Value, lastSeen, isOnline, "legacy");
                    count++;
                }
            }
        }

        LogInfo(logger, "Legacy devices scanned: " + count);
    }

    private static void Merge(
        Dictionary<string, TvDevice> dict,
        string originalName,
        long tvId,
        DateTime? lastSeen,
        bool isOnline,
        string source)
    {
        var key = Normalize(originalName);

        if (string.IsNullOrEmpty(key))
            return;

        var candidate = new TvDevice
        {
            TeamviewerId = tvId,
            LastSeen = lastSeen,
            IsOnline = isOnline,
            OriginalName = originalName,
            Source = source
        };

        TvDevice existing;

        if (!dict.TryGetValue(key, out existing))
        {
            dict[key] = candidate;
            return;
        }

        if (IsBetterCandidate(candidate, existing))
            dict[key] = candidate;
    }

    private static bool IsBetterCandidate(TvDevice candidate, TvDevice existing)
    {
        if (candidate.IsOnline && !existing.IsOnline)
            return true;

        if (!candidate.IsOnline && existing.IsOnline)
            return false;

        var candidateTs = candidate.LastSeen ?? DateTime.MinValue;
        var existingTs = existing.LastSeen ?? DateTime.MinValue;

        if (candidateTs > existingTs)
            return true;

        if (candidateTs < existingTs)
            return false;

        if (candidate.Source == "managed" && existing.Source != "managed")
            return true;

        return false;
    }

    private static JObject GetJson(HttpClient client, string url)
    {
        using (var req = new HttpRequestMessage(HttpMethod.Get, url))
        {
            var resp = client.SendAsync(req).Result;
            var body = resp.Content.ReadAsStringAsync().Result;

            if (!resp.IsSuccessStatusCode)
                throw new Exception("HTTP " + (int)resp.StatusCode + " from " + url + ": " + body);

            return JObject.Parse(body);
        }
    }

    private static string Normalize(string value)
    {
        if (string.IsNullOrWhiteSpace(value))
            return null;

        var x = value.Trim().ToLowerInvariant();

        var dot = x.IndexOf('.');
        if (dot > 0)
            x = x.Substring(0, dot);

        var dash = x.IndexOf(" - ");
        if (dash > 0)
            x = x.Substring(0, dash);

        x = x.Trim();

        return string.IsNullOrWhiteSpace(x) ? null : x;
    }

    private static void LogInfo(NLog.ILogger logger, string message)
    {
        if (Settings.EnableLogging)
            logger.Info("TeamViewerImport: " + message);
    }

    private class AlvaoComputer
    {
        public int NodeId { get; set; }
        public int ClassId { get; set; }
        public string Hostname { get; set; }
        public string CurrentTeamviewerId { get; set; }
    }

    private class TvDevice
    {
        public long TeamviewerId { get; set; }
        public DateTime? LastSeen { get; set; }
        public bool IsOnline { get; set; }
        public string OriginalName { get; set; }
        public string Source { get; set; }
    }
}
